import React, { useState } from 'react';


function Register() {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    service: 'Web Development',
    message: ''
  });

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log("Form Data Submitted:", formData);
    alert("Thank you! Your request for " + formData.service + " has been received.");
  };

  return (
    <div className="register-page bg-light py-5" style={{ minHeight: '90vh' }}>
      <div className="container">
        <div className="row justify-content-center">
          <div className="col-md-6">
            <div className="card shadow border-0 p-4">
              <div className="card-body">
                <h2 className="fw-bold text-center mb-4">Book a Service</h2>
                <p className="text-center text-muted mb-4">Fill out the form below and I'll get back to you shortly.</p>
                
                <form onSubmit={handleSubmit}>
                  {/* Name Field */}
                  <div className="mb-3">
                    <label className="form-label fw-bold">Full Name</label>
                    <input 
                      type="text" 
                      name="name"
                      className="form-control" 
                      placeholder="Enter your name" 
                      required 
                      onChange={handleChange}
                    />
                  </div>

                  {/* Email Field */}
                  <div className="mb-3">
                    <label className="form-label fw-bold">Email Address</label>
                    <input 
                      type="email" 
                      name="email"
                      className="form-control" 
                      placeholder="name@example.com" 
                      required 
                      onChange={handleChange}
                    />
                  </div>

                  {/* Service Selection */}
                  <div className="mb-3">
                    <label className="form-label fw-bold">Select Service</label>
                    <select 
                      name="service" 
                      className="form-select" 
                      onChange={handleChange}
                      value={formData.service}
                    >
                      <option value="Web Development">Web Development</option>
                      <option value="UI/UX Design">UI/UX Design</option>
                      <option value="App Development">App Development</option>
                      <option value="Assignment Support">Assignment Support</option>
                      <option value="PPT Design">PPT Design</option>
                      <option value="Report Writing">Report Writing</option>
                    </select>
                  </div>

                  {/* Message Field */}
                  <div className="mb-4">
                    <label className="form-label fw-bold">Project Details (Optional)</label>
                    <textarea 
                      name="message"
                      className="form-control" 
                      rows="4" 
                      placeholder="Briefly describe your requirements..."
                      onChange={handleChange}
                    ></textarea>
                  </div>

                  {/* Submit Button */}
                  <button type="submit" className="btn btn-primary w-100 fw-bold py-2 shadow-sm">
                    Submit Request
                  </button>
                </form>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Register;
